import React from 'react';
import { Container, Row, Col } from 'react-bootstrap';
// Asumimos que estos componentes existen en la carpeta components
import LoadingSpinner from './LoadingSpinner'; 
import Message from './Message'; 
import Product from './Product'; // Tarjeta de producto (debe existir)
import Paginate from './Paginate'; // Componente de paginación (debe existir)

// Mocks para que la vista cargue y el diseño se vea completo.
const MOCK_PRODUCTS = [
  { _id: '1', name: 'Deona Pexnnices (Smartwatch)', price: 199.99, sku: 'DRN001', rating: 4.5, numReviews: 12, countInStock: 5, image: 'https://placehold.co/400x300/F1F5F9/0F172A?text=WATCH', productType: 'IN_HOUSE' },
  { _id: '2', name: 'Trps del Tib (VR Headset)', price: 299.99, sku: 'VR001', rating: 5, numReviews: 25, countInStock: 10, isOffer: true, image: 'https://placehold.co/400x300/F1F5F9/0F172A?text=VR+HEADSET', productType: 'IN_HOUSE' },
  { _id: '3', name: 'Pnda de Tvler (Batería)', price: 49.99, sku: 'DRN002', rating: 3.5, numReviews: 8, countInStock: 0, image: 'https://placehold.co/400x300/F1F5F9/0F172A?text=BATTERY', productType: 'IN_HOUSE' },
];

function ProductList({ 
    products = MOCK_PRODUCTS, 
    loading = false, 
    error = null,
    pages = 1,
    page = 1,
    setPage = () => {} 
}) {
    
    // Si está cargando, mostramos el spinner
    if (loading) return <LoadingSpinner />; 
    
    // Si hay un error, mostramos el mensaje de alerta
    if (error) return <Container><Message variant="danger">{error}</Message></Container>; 

    // Renderizado de la cuadrícula de productos
    return (
        <>
            <h2 className="text-3xl font-bold text-[#0F172A] tracking-tight m-0 mb-4 pb-2 border-b border-gray-200">
                Nuestros Productos
            </h2>
            
            {/* Si no hay productos */}
            {(!products || products.length === 0) ? (
                <div className="text-center py-5 border border-dashed border-gray-300 rounded-xl">
                    <i className="fas fa-box-open fa-4x text-gray-300 mb-4"></i>
                    <h4 className="text-gray-600 font-bold">¡Lo sentimos! No hay productos en esta sección.</h4>
                </div>
            ) : (
                <>
                    {/* Renderizado de la cuadrícula de productos */}
                    <Row>
                        {products.map((product) => (
                            // Layout Responsivo: 1 en móvil, 2 en tablet, 3 en desktop
                            <Col key={product._id} sm={12} md={6} lg={4} className="d-flex align-items-stretch mb-5">
                                <Product product={product} />
                            </Col>
                        ))}
                    </Row>
                    
                    {/* Paginación (solo si hay más de una página) */}
                    {(pages > 1) && (
                        <div className="d-flex justify-content-center mt-5">
                            <Paginate pages={pages} page={page} setPage={setPage} />
                        </div>
                    )}
                </>
            )}
        </>
    );
};

export default ProductList;
